Set-Content -Path "c:\Users\User\Documents\ddd\2026spring\portfolio\css\style.css" -Value @'
*
{
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

html
{
    scroll-behavior: smooth;
}

body
{
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    line-height: 1.6;
    color: #333;
    background-color: #f4f4f4;
}

.container
{
    max-width: 1200px;
    margin: 0 auto;
    padding: 0 20px;
}

/* Navigation */
.navbar
{
    background-color: #2c3e50;
    color: white;
    padding: 1rem 0;
    position: fixed;
    width: 100%;
    top: 0;
    z-index: 1000;
    box-shadow: 0 2px 5px rgba(0,0,0,0.1);
}

.nav-container
{
    max-width: 1200px;
    margin: 0 auto;
    padding: 0 20px;
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.nav-logo a
{
    color: white;
    font-size: 1.5rem;
    font-weight: bold;
    text-decoration: none;
}

.nav-menu
{
    display: flex;
    list-style: none;
    gap: 2rem;
}

.nav-link
{
    color: white;
    text-decoration: none;
    transition: color 0.3s;
}

.nav-link:hover,
.nav-link.active
{
    color: #3498db;
}

.nav-toggle
{
    display: none;
    flex-direction: column;
    cursor: pointer;
}

.bar
{
    width: 25px;
    height: 3px;
    background-color: white;
    margin: 3px 0;
    transition: 0.3s;
}

/* Main Content */
main
{
    margin-top: 80px;
}

.section-title
{
    color: #2c3e50;
    margin-bottom: 1.5rem;
    font-size: 2rem;
}

.text-muted
{
    color: #7f8c8d;
}

/* Hero Section */
.hero
{
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: white;
    padding: 4rem 0;
}

.hero-container
{
    max-width: 1200px;
    margin: 0 auto;
    padding: 0 20px;
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 3rem;
    align-items: center;
}

.profile-section
{
    display: flex;
    justify-content: center;
}

.profile-image-container
{
    position: relative;
    width: 250px;
    height: 250px;
}

.profile-image
{
    width: 100%;
    height: 100%;
    border-radius: 50%;
    object-fit: cover;
    border: 5px solid white;
    box-shadow: 0 5px 15px rgba(0,0,0,0.2);
}

.profile-overlay
{
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    opacity: 0;
    transition: opacity 0.3s;
    background-color: rgba(0,0,0,0.5);
    width: 100%;
    height: 100%;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
}

.profile-image-container:hover .profile-overlay
{
    opacity: 1;
}

.profile-overlay i
{
    color: white;
    font-size: 2rem;
}

.content-section
{
    text-align: left;
}

.hero-title
{
    font-size: 3rem;
    margin-bottom: 1rem;
    text-shadow: 2px 2px 4px rgba(0,0,0,0.3);
}

.hero-subtitle
{
    font-size: 1.5rem;
    margin-bottom: 2rem;
    color: #ecf0f1;
}

.hero-description
{
    font-size: 1.1rem;
    margin-bottom: 1rem;
    line-height: 1.8;
}

.hero-buttons
{
    display: flex;
    gap: 1rem;
    margin-top: 2rem;
}

.btn
{
    padding: 12px 30px;
    border: none;
    border-radius: 5px;
    text-decoration: none;
    font-weight: bold;
    transition: all 0.3s;
    display: inline-flex;
    align-items: center;
    justify-content: center;
}

.btn-primary
{
    background-color: #3498db;
    color: white;
}

.btn-primary:hover
{
    background-color: #2980b9;
    transform: translateY(-2px);
}

.btn-secondary
{
    background-color: transparent;
    color: white;
    border: 2px solid white;
}

.btn-secondary:hover
{
    background-color: white;
    color: #2c3e50;
}

/* Stats Section */
.stats-section
{
    padding: 4rem 0;
    background-color: white;
}

.stats-grid
{
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: 2rem;
    text-align: center;
}

.stat-item
{
    padding: 2rem;
    background: #f8f9fa;
    border-radius: 15px;
    transition: transform 0.3s, box-shadow 0.3s, opacity 0.3s;
}

.stat-item.animated
{
    transform: translateY(0);
    opacity: 1;
}

.stat-item:not(.animated)
{
    transform: translateY(20px);
    opacity: 0;
}

.stat-icon
{
    font-size: 2rem;
    color: #3498db;
    margin-bottom: 1rem;
}

.stat-number
{
    font-size: 2rem;
    margin-bottom: 0.5rem;
}

.stat-label
{
    color: #7f8c8d;
}

/* About Section */
.about-content
{
    padding: 4rem 0;
    background-color: white;
}

.about-grid
{
    display: grid;
    grid-template-columns: 1.2fr 0.8fr;
    gap: 3rem;
    align-items: center;
}

.about-intro p,
.about-card p,
.experience-description,
.education-description
{
    font-size: 1.1rem;
    line-height: 1.8;
    color: #555;
    margin-bottom: 1rem;
}

.about-image
{
    width: 100%;
    border-radius: 10px;
    box-shadow: 0 5px 15px rgba(0,0,0,0.1);
}

.about-cards,
.activity-grid
{
    display: grid;
    gap: 2rem;
}

.about-card,
.activity-card,
.project-card,
.sidebar-card
{
    background: #f8f9fa;
    padding: 2rem;
    border-radius: 15px;
    box-shadow: 0 5px 15px rgba(0,0,0,0.05);
}

.about-card h3,
.activity-card h3,
.project-title,
.experience-title,
.education-title,
.sidebar-card h3
{
    color: #2c3e50;
    margin-bottom: 1rem;
}

.about-card ul,
.skills-list li,
.certifications-list li,
.contact-info li
{
    list-style: none;
    padding: 0;
}

.about-card li,
.skills-list li,
.certifications-list li,
.contact-info li
{
    line-height: 1.8;
}

.about-card li i,
.contact-info li i,
.certifications-list li i
{
    margin-right: 0.75rem;
    color: #27ae60;
}

.activity-grid
{
    grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
}

.activity-card
{
    color: white;
    min-height: 220px;
}

.activity-card:nth-child(1)
{
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
}

.activity-card:nth-child(2)
{
    background: linear-gradient(135deg, #f093fb 0%, #f5576c 100%);
}

.activity-card:nth-child(3)
{
    background: linear-gradient(135deg, #4facfe 0%, #00f2fe 100%);
}

.activity-card:nth-child(4)
{
    background: linear-gradient(135deg, #43e97b 0%, #38f9d7 100%);
}

.activity-card p
{
    color: rgba(255,255,255,0.95);
}

.activity-card i
{
    margin-right: 0.75rem;
    color: #ffffff;
}

/* Projects Section */
.projects-section
{
    padding: 4rem 0;
    background-color: #f8f9fa;
}

.projects-grid
{
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
    gap: 2rem;
    margin-top: 2rem;
}

.project-card
{
    background: white;
    border-radius: 15px;
    overflow: hidden;
    box-shadow: 0 5px 15px rgba(0,0,0,0.1);
    transition: transform 0.3s, box-shadow 0.3s;
}

.project-card:hover
{
    transform: translateY(-10px);
    box-shadow: 0 15px 30px rgba(0,0,0,0.2);
}

.project-image
{
    width: 100%;
    height: 240px;
    object-fit: cover;
}

.project-content
{
    padding: 1.5rem;
}

.project-tag
{
    display: inline-block;
    background: #3498db;
    color: white;
    padding: 0.25rem 0.75rem;
    border-radius: 20px;
    font-size: 0.85rem;
    margin-bottom: 1rem;
}

.project-title
{
    color: #2c3e50;
    margin-bottom: 1rem;
    font-size: 1.6rem;
}

.project-description
{
    color: #7f8c8d;
    line-height: 1.7;
    margin-bottom: 1rem;
}

.project-tech
{
    display: flex;
    flex-wrap: wrap;
    gap: 0.5rem;
    margin-top: 1rem;
}

.tech-badge
{
    background: #ecf0f1;
    color: #2c3e50;
    padding: 0.35rem 0.85rem;
    border-radius: 15px;
    font-size: 0.85rem;
}

.project-links
{
    display: flex;
    gap: 1rem;
    margin-top: 1rem;
    flex-wrap: wrap;
}

.project-link
{
    color: #3498db;
    text-decoration: none;
    display: flex;
    align-items: center;
    gap: 0.5rem;
    transition: color 0.3s;
}

.project-link:hover
{
    color: #2980b9;
}

/* Resume Section */
.resume-section
{
    padding: 4rem 0;
    background-color: white;
}

.resume-container
{
    max-width: 1000px;
    margin: 0 auto;
    padding: 0 20px;
}

.resume-header
{
    text-align: center;
    margin-bottom: 3rem;
}

.resume-header h1
{
    color: #2c3e50;
    margin-bottom: 0.5rem;
}

.resume-header p
{
    color: #7f8c8d;
    font-size: 1.1rem;
}

.resume-content
{
    display: grid;
    grid-template-columns: 2fr 1fr;
    gap: 3rem;
}

.experience-item,
.education-item
{
    margin-bottom: 2rem;
}

.experience-header,
.education-header
{
    display: flex;
    justify-content: space-between;
    margin-bottom: 0.5rem;
    flex-wrap: wrap;
    gap: 1rem;
}

.experience-title,
.education-title
{
    color: #2c3e50;
    font-weight: bold;
}

.experience-date,
.education-date
{
    color: #3498db;
    font-weight: bold;
}

.experience-company,
.education-school
{
    color: #e74c3c;
    margin-bottom: 0.5rem;
}

.experience-description,
.education-description
{
    color: #7f8c8d;
    line-height: 1.7;
}

.skills-list,
.certifications-list,
.contact-info
{
    list-style: none;
    padding: 0;
    margin: 0;
}

.skills-list li
{
    padding: 0.85rem 0;
    border-bottom: 1px solid #ecf0f1;
    display: flex;
    justify-content: space-between;
}

.skill-name,
.skill-level
{
    color: #2c3e50;
}

.sidebar-card
{
    background: #f8f9fa;
    padding: 1.75rem;
    border-radius: 15px;
    margin-bottom: 2rem;
}

.sidebar-card h3
{
    color: #2c3e50;
    margin-bottom: 1rem;
}

.contact-info li,
.certifications-list li
{
    margin-bottom: 0.85rem;
    display: flex;
    align-items: center;
}

.contact-info li i,
.certifications-list li i
{
    color: #3498db;
    width: 22px;
}

.download-btn
{
    display: inline-block;
    background: #3498db;
    color: white;
    padding: 12px 30px;
    text-decoration: none;
    border-radius: 5px;
    font-weight: bold;
    transition: background 0.3s;
    margin-top: 1rem;
}

.download-btn:hover
{
    background: #2980b9;
}

/* Footer */
.footer
{
    background-color: #2c3e50;
    color: white;
    padding: 3rem 0 1.5rem;
}

.footer-container
{
    max-width: 1200px;
    margin: 0 auto;
    padding: 0 20px;
}

.footer-content
{
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
    gap: 2rem;
    padding-bottom: 2rem;
}

.footer-section h4,
.footer-section h3
{
    margin-bottom: 1rem;
}

.footer-links,
.social-links
{
    list-style: none;
    padding: 0;
    margin: 0;
}

.footer-links li
{
    margin-bottom: 0.75rem;
}

.footer-links a,
.footer-section a
{
    color: white;
    text-decoration: none;
}

.footer-links a:hover,
.footer-section a:hover
{
    color: #3498db;
}

.social-links
{
    display: flex;
    gap: 0.75rem;
    flex-wrap: wrap;
}

.social-link
{
    color: white;
    font-size: 1.4rem;
}

.repo-link
{
    margin-top: 1rem;
}

.repo-link a
{
    color: white;
    text-decoration: underline;
}

.footer-bottom
{
    border-top: 1px solid rgba(255,255,255,0.15);
    padding-top: 1rem;
    text-align: center;
    color: #dfe6e9;
    font-size: 0.95rem;
}

/* Responsive */
@media (max-width: 1024px)
{
    .hero-container,
    .about-grid,
    .resume-content
    {
        grid-template-columns: 1fr;
    }

    .nav-menu
    {
        gap: 1rem;
    }
}

@media (max-width: 768px)
{
    .nav-toggle
    {
        display: flex;
    }

    .nav-menu
    {
        position: absolute;
        top: 100%;
        right: 0;
        background-color: #2c3e50;
        width: 100%;
        max-width: 280px;
        flex-direction: column;
        align-items: flex-start;
        padding: 1.5rem;
        gap: 1rem;
        display: none;
    }

    .nav-menu.active
    {
        display: flex;
    }

    .main-content,
    .sidebar
    {
        width: 100%;
    }

    .hero
    {
        padding: 3rem 0;
    }

    .hero-title
    {
        font-size: 2.4rem;
    }

    .hero-subtitle
    {
        font-size: 1.25rem;
    }

    .hero-buttons
    {
        flex-direction: column;
        align-items: stretch;
    }

    .project-image
    {
        height: 220px;
    }
}

@media (max-width: 540px)
{
    .navbar
    {
        padding: 0.75rem 0;
    }

    .nav-logo a
    {
        font-size: 1.25rem;
    }

    .hero-title
    {
        font-size: 2rem;
    }

    .btn
    {
        width: 100%;
        text-align: center;
    }
}
