*
{
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

html
{
    scroll-behavior: smooth;
}

body
{
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    line-height: 1.6;
    color: #333;
    background-color: #f4f4f4;
}

.container
{
    max-width: 1200px;
    margin: 0 auto;
    padding: 0 20px;
}

/* Navigation */
.navbar
{
    background-color: #2c3e50;
    color: white;
    padding: 1rem 0;
    position: fixed;
    width: 100%;
    top: 0;
    z-index: 1000;
    box-shadow: 0 2px 5px rgba(0,0,0,0.1);
}

.nav-container
{
    max-width: 1200px;
    margin: 0 auto;
    padding: 0 20px;
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.nav-logo a
{
    color: white;
    font-size: 1.5rem;
    font-weight: bold;
    text-decoration: none;
}

.nav-menu
{
    display: flex;
    list-style: none;
    gap: 2rem;
}

.nav-link
{
    color: white;
    text-decoration: none;
    transition: color 0.3s;
}

.nav-link:hover,
.nav-link.active
{
    color: #3498db;
}

.nav-toggle
{
    display: none;
    flex-direction: column;
    cursor: pointer;
}

.bar
{
    width: 25px;
    height: 3px;
    background-color: white;
    margin: 3px 0;
    transition: 0.3s;
}

/* Main Content */
main
{
    margin-top: 80px;
}

.section-title
{
    color: #2c3e50;
    margin-bottom: 1.5rem;
    font-size: 2rem;
}

.text-muted
{
    color: #7f8c8d;
}

