    color: white;
    padding: 4rem 0;
}

.hero-container
{
    max-width: 1200px;
    margin: 0 auto;
    padding: 0 20px;
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 3rem;
    align-items: center;
}

.profile-section
{
    display: flex;
    justify-content: center;
}

.profile-image-container
