    width: 250px;
    height: 250px;
}

.profile-image
{
    width: 100%;
    height: 100%;
    border-radius: 50%;
    object-fit: cover;
    border: 5px solid white;
    box-shadow: 0 5px 15px rgba(0,0,0,0.2);
}

.profile-overlay
{
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    opacity: 0;
    transition: opacity 0.3s;
    background-color: rgba(0,0,0,0.5);
    width: 100%;
    height: 100%;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
}

.profile-image-container:hover .profile-overlay
{
    opacity: 1;
}

.profile-overlay i
{
    color: white;
    font-size: 2rem;
}

.content-section
{
    text-align: left;
}

.hero-title
{
    font-size: 3rem;
    margin-bottom: 1rem;
    text-shadow: 2px 2px 4px rgba(0,0,0,0.3);
}

.hero-subtitle
{
    font-size: 1.5rem;
    margin-bottom: 2rem;
    color: #ecf0f1;
}

.hero-description
{
    font-size: 1.1rem;
    margin-bottom: 1rem;
    line-height: 1.8;
}

.hero-buttons
{
    display: flex;
    gap: 1rem;
    margin-top: 2rem;
}

.btn
{
    padding: 12px 30px;
    border: none;
    border-radius: 5px;
    text-decoration: none;
    font-weight: bold;
    transition: all 0.3s;
    display: inline-flex;
    align-items: center;
    justify-content: center;
}

.btn-primary
{
    background-color: #3498db;
