.activity-card p
{
    color: rgba(255,255,255,0.95);
}

.activity-card i
{
    margin-right: 0.75rem;
    color: #ffffff;
}

/* Projects Section */
.projects-section
{
    padding: 4rem 0;
    background-color: #f8f9fa;
}

.projects-grid
{
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
    gap: 2rem;
    margin-top: 2rem;
}

.project-card
{
    background: white;
    border-radius: 15px;
    overflow: hidden;
    box-shadow: 0 5px 15px rgba(0,0,0,0.1);
    transition: transform 0.3s, box-shadow 0.3s;
}

.project-card:hover
{
    transform: translateY(-10px);
    box-shadow: 0 15px 30px rgba(0,0,0,0.2);
}

.project-image
{
    width: 100%;
    height: 240px;
    object-fit: cover;
}

.project-content
{
    padding: 1.5rem;
}

.project-tag
{
    display: inline-block;
    background: #3498db;
    color: white;
    padding: 0.25rem 0.75rem;
    border-radius: 20px;
    font-size: 0.85rem;
    margin-bottom: 1rem;
}

.project-title
{
    color: #2c3e50;
    margin-bottom: 1rem;
    font-size: 1.6rem;
}

.project-description
{
    color: #7f8c8d;
    line-height: 1.7;
    margin-bottom: 1rem;
}

.project-tech
{
    display: flex;
    flex-wrap: wrap;
    gap: 0.5rem;
    margin-top: 1rem;
}

.tech-badge
{
    background: #ecf0f1;
    color: #2c3e50;
    padding: 0.35rem 0.85rem;
    border-radius: 15px;
    font-size: 0.85rem;
}

.project-links
{
    display: flex;
    gap: 1rem;
    margin-top: 1rem;
    flex-wrap: wrap;
}

.project-link
{
    color: #3498db;
    text-decoration: none;
    display: flex;
    align-items: center;
    gap: 0.5rem;
    transition: color 0.3s;
}

.project-link:hover
{
    color: #2980b9;
}

/* Resume Section */
.resume-section
{
    padding: 4rem 0;
    background-color: white;
}

.resume-container
{
    max-width: 1000px;
    margin: 0 auto;
    padding: 0 20px;
}

.resume-header
{
    text-align: center;
    margin-bottom: 3rem;
}

.resume-header h1
{
    color: #2c3e50;
    margin-bottom: 0.5rem;
}

.resume-header p
{
    color: #7f8c8d;
    font-size: 1.1rem;
}

.resume-content
{
    display: grid;
    grid-template-columns: 2fr 1fr;
    gap: 3rem;
}

.experience-item,
.education-item
{
    margin-bottom: 2rem;
}

.experience-header,
.education-header
{
    display: flex;
    justify-content: space-between;
