    flex-wrap: wrap;
    gap: 1rem;
}

.experience-title,
.education-title
{
    color: #2c3e50;
    font-weight: bold;
}

.experience-date,
.education-date
{
    color: #3498db;
    font-weight: bold;
}

.experience-company,
.education-school
{
    color: #e74c3c;
    margin-bottom: 0.5rem;
}

.experience-description,
.education-description
{
    color: #7f8c8d;
    line-height: 1.7;
}

.skills-list,
.certifications-list,
.contact-info
{
    list-style: none;
    padding: 0;
    margin: 0;
}

.skills-list li
{
    padding: 0.85rem 0;
    border-bottom: 1px solid #ecf0f1;
    display: flex;
    justify-content: space-between;
}

.skill-name,
.skill-level
{
    color: #2c3e50;
}

.sidebar-card
{
    background: #f8f9fa;
    padding: 1.75rem;
    border-radius: 15px;
    margin-bottom: 2rem;
}

.sidebar-card h3
{
    color: #2c3e50;
    margin-bottom: 1rem;
}

.contact-info li,
.certifications-list li
{
    margin-bottom: 0.85rem;
    display: flex;
    align-items: center;
}

.contact-info li i,
.certifications-list li i
{
    color: #3498db;
    width: 22px;
}

.download-btn
{
    display: inline-block;
    background: #3498db;
    color: white;
    padding: 12px 30px;
    text-decoration: none;
    border-radius: 5px;
    font-weight: bold;
    transition: background 0.3s;
    margin-top: 1rem;
}

.download-btn:hover
{
    background: #2980b9;
}

/* Footer */
.footer
{
    background-color: #2c3e50;
    color: white;
    padding: 3rem 0 1.5rem;
}

.footer-container
{
    max-width: 1200px;
    margin: 0 auto;
    padding: 0 20px;
}

.footer-content
{
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
    gap: 2rem;
    padding-bottom: 2rem;
}

.footer-section h4,
.footer-section h3
{
    margin-bottom: 1rem;
}

.footer-links,
.social-links
{
    list-style: none;
    padding: 0;
    margin: 0;
}

.footer-links li
{
    margin-bottom: 0.75rem;
}

.footer-links a,
.footer-section a
{
    color: white;
    text-decoration: none;
}

.footer-links a:hover,
.footer-section a:hover
{
    color: #3498db;
}

.social-links
{
    display: flex;
    gap: 0.75rem;
    flex-wrap: wrap;
}

.social-link
{
    color: white;
    font-size: 1.4rem;
}

.repo-link
{
    margin-top: 1rem;
}

.repo-link a
{
    color: white;
    text-decoration: underline;
}

.footer-bottom
{
    border-top: 1px solid rgba(255,255,255,0.15);
    padding-top: 1rem;
    text-align: center;
    color: #dfe6e9;
    font-size: 0.95rem;
}

/* Responsive */
@media (max-width: 1024px)
{
    .hero-container,
    .about-grid,
    .resume-content
    {
        grid-template-columns: 1fr;
    }

    .nav-menu
    {
        gap: 1rem;
    }
}

@media (max-width: 768px)
{
    .nav-toggle
    {
        display: flex;
    }

    .nav-menu
    {
        position: absolute;
        top: 100%;
        right: 0;
        background-color: #2c3e50;
        width: 100%;
        max-width: 280px;
        flex-direction: column;
        align-items: flex-start;
        padding: 1.5rem;
        gap: 1rem;
        display: none;
    }

    .nav-menu.active
    {
        display: flex;
    }

    .main-content,
    .sidebar
    {
        width: 100%;
    }

    .hero
    {
        padding: 3rem 0;
    }

    .hero-title
    {
        font-size: 2.4rem;
    }

    .hero-subtitle
    {
        font-size: 1.25rem;
    }

    .hero-buttons
    {
        flex-direction: column;
        align-items: stretch;
    }

    .project-image
    {
        height: 220px;
    }
}

@media (max-width: 540px)
{
    .navbar
    {
        padding: 0.75rem 0;
    }

    .nav-logo a
    {
        font-size: 1.25rem;
    }

    .hero-title
    {
        font-size: 2rem;
    }

    .btn
    {
        width: 100%;
        text-align: center;
    }
}
