import React, { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { navigationItems, portfolioInfo } from '../config/navigationConfig';
import '../styles/Navbar.css';

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);
  const location = useLocation();

  const toggleMobileMenu = () => {
    setIsOpen(!isOpen);
  };

  const closeMobileMenu = () => {
    setIsOpen(false);
  };

  return (
    <nav className="navbar">
      <div className="nav-container">
        <div className="nav-logo">
          <Link to="/" onClick={closeMobileMenu}>
            {portfolioInfo.title}
          </Link>
        </div>
        <ul className={`nav-menu ${isOpen ? 'active' : ''}`}>
          {navigationItems.map((item) => (
            <li className="nav-item" key={item.id}>
              <Link
                to={item.path}
                className={`nav-link ${
                  location.pathname === item.path ? 'active' : ''
                }`}
                onClick={closeMobileMenu}
              >
                {item.label}
              </Link>
            </li>
          ))}
        </ul>
        <div
          className={`nav-toggle ${isOpen ? 'active' : ''}`}
          id="mobile-menu"
          onClick={toggleMobileMenu}
        >
          <span className="bar"></span>
          <span className="bar"></span>
          <span className="bar"></span>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;

import React from 'react';
import { Link } from 'react-router-dom';
import { navigationItems, socialLinks, portfolioInfo } from '../config/navigationConfig';
import '../styles/Footer.css';

const Footer = () => {
  const footerSocialLinks = socialLinks.filter(link => link.showInFooter);

  return (
    <footer className="footer">
      <div className="footer-container">
        <div className="footer-content">
          <div className="footer-section">
            <h3>{portfolioInfo.title}</h3>
            <p>Showcasing my journey in technology and development.</p>
          </div>
          <div className="footer-section">
            <h4>Quick Links</h4>
            <ul className="footer-links">
              {navigationItems.map((item) => (
                <li key={item.id}>
                  <Link to={item.path}>
                    <i className="fas fa-link"></i> {item.label}
                  </Link>
                </li>
              ))}
            </ul>
          </div>
          <div className="footer-section">
            <h4>Connect With Me</h4>
            <div className="social-links">
              {footerSocialLinks.map((link, index) => (
                <a
                  key={index}
                  href={link.url}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="social-link"
                  aria-label={link.label}
                >
                  <i className={link.icon}></i>
                </a>
              ))}
            </div>
            <p className="repo-link">
              <i className="fab fa-github"></i>
              <a href={portfolioInfo.githubRepo} target="_blank" rel="noopener noreferrer">
                View GitHub Repository
              </a>
            </p>
          </div>
        </div>
        <div className="footer-bottom">
          <p>
            &copy; {portfolioInfo.copyYear} {portfolioInfo.title}. All rights reserved. |
            Designed with <i className="fas fa-heart"></i>
          </p>
        </div>
      </div>
    </footer>
  );
};

export default Footer;

